"""matplotlib.widgets — interactive widget stubs."""


class Widget:
    drawon = True
    eventson = True
    _active = True

    def set_active(self, active): self._active = active
    def get_active(self): return self._active
    def ignore(self, event): return not self._active


class AxesWidget(Widget):
    def __init__(self, ax):
        self.ax = ax
        self.cids = []

    def connect_event(self, event, callback):
        pass

    def disconnect_events(self):
        pass


class Button(AxesWidget):
    def __init__(self, ax, label, image=None, color='0.85', hovercolor='0.95'):
        super().__init__(ax)
        self.label = label
        self.color = color
        self.hovercolor = hovercolor

    def on_clicked(self, func):
        pass

    def disconnect(self, cid):
        pass


class Slider(AxesWidget):
    def __init__(self, ax, label, valmin, valmax, *, valinit=0.5,
                 valfmt=None, closedmin=True, closedmax=True, slidermin=None,
                 slidermax=None, dragging=True, valstep=None, orientation='horizontal',
                 initcolor='r', track_color='lightblue', handle_style=None, **kwargs):
        super().__init__(ax)
        self.label = label
        self.valmin = valmin
        self.valmax = valmax
        self.val = valinit
        self.valinit = valinit
        self.valstep = valstep
        self.orientation = orientation

    def on_changed(self, func): pass
    def set_val(self, val): self.val = val
    def reset(self): self.val = self.valinit
    def disconnect(self, cid): pass


class RangeSlider(Slider):
    def __init__(self, ax, label, valmin, valmax, valinit=None, **kwargs):
        super().__init__(ax, label, valmin, valmax, **kwargs)
        self.val = valinit or (valmin, valmax)


class TextBox(AxesWidget):
    def __init__(self, ax, label, initial='', color='.95', hovercolor='1',
                 label_pad=.01, textalignment='left'):
        super().__init__(ax)
        self.text = initial

    def on_text_change(self, func): pass
    def on_submit(self, func): pass
    def set_val(self, val): self.text = val
    def disconnect(self, cid): pass


class CheckButtons(AxesWidget):
    def __init__(self, ax, labels, actives=None, *, useblit=True,
                 label_props=None, frame_props=None, check_props=None):
        super().__init__(ax)
        self.labels = labels
        self.actives = actives or [False] * len(labels)

    def get_status(self): return list(self.actives)
    def set_active(self, index):
        self.actives[index] = not self.actives[index]
    def on_clicked(self, func): pass
    def disconnect(self, cid): pass


class RadioButtons(AxesWidget):
    def __init__(self, ax, labels, active=0, activecolor=None, *,
                 useblit=True, label_props=None, radio_props=None):
        super().__init__(ax)
        self.labels = labels
        self.value_selected = labels[active] if labels else None
        self.activecolor = activecolor

    def on_clicked(self, func): pass
    def set_active(self, index): pass
    def disconnect(self, cid): pass


class Cursor(AxesWidget):
    def __init__(self, ax, *, horizOn=True, vertOn=True, useblit=False, **lineprops):
        super().__init__(ax)


class MultiCursor(Widget):
    def __init__(self, canvas, axes, *, useblit=True, horizOn=False, vertOn=True, **lineprops):
        self.axes = axes


class SpanSelector(AxesWidget):
    def __init__(self, ax, onselect, direction, *, minspan=0, useblit=False,
                 props=None, onmove_callback=None, interactive=False,
                 button=None, handle_props=None, grab_range=10,
                 drag_from_anywhere=False, ignore_event_outside=False,
                 snap_values=None):
        super().__init__(ax)
        self.direction = direction


class RectangleSelector(AxesWidget):
    def __init__(self, ax, onselect, *, minspanx=0, minspany=0, useblit=False,
                 props=None, spancoords='data', button=None, grab_range=10,
                 handle_props=None, interactive=False, state_modifier_keys=None,
                 drag_from_anywhere=False, ignore_event_outside=False,
                 use_data_coordinates=False):
        super().__init__(ax)


class EllipseSelector(RectangleSelector):
    pass


class LassoSelector(AxesWidget):
    def __init__(self, ax, onselect, *, useblit=True, props=None, button=None):
        super().__init__(ax)


class PolygonSelector(AxesWidget):
    def __init__(self, ax, onselect, *, useblit=False, props=None,
                 handle_props=None, grab_range=10, draw_bounding_box=False,
                 box_handle_props=None, box_props=None):
        super().__init__(ax)
